#include <stdio.h>
int main(){
    int N; if(scanf("%d",&N)!=1) return 0;
    long long sum=0;
    for(int i=0;i<N;++i){
        int x; scanf("%d",&x);
        sum+=x;
        printf("%lld",sum);
        if(i+1<N) printf(" ");
    }
    printf("\n");
    return 0;
}

